# frozen_string_literal: true

require_relative '../../utils/basic_test_class'

module AUPSTestKit
  # The recommended sections populated in the Composition resource.
  class AUPSSummaryBundleCompositionRecommendedSection100ballot < BasicTest
    title 'Composition contains recommended sections with entry references'
    description 'Displays information about recommended sections'
    id :au_ps_summary_bundle_composition_recommended_sections_100ballot

    
    run do
      read_composition_sections_info([{:id=>"Composition.section:sectionImmunizations", :short=>"Patient Summary Immunizations Section", :definition=>"Information about a patient's current immunisation status and pertinent immunisation history.\r\nThe primary use case for this section is to enable communication of a patient's immunisation status.\r\nIt could contain the entire immunisation history that is relevant to the period of time being summarised.", :min=>0, :max=>"1", :required=>false, :mustSupport=>true, :code=>"11369-6", :entries=>[{:id=>"Composition.section:sectionImmunizations.entry:immunization", :min=>0, :max=>"*", :required=>false, :mustSupport=>true, :profiles=>["Immunization|http://hl7.org.au/fhir/ps/StructureDefinition/au-ps-immunization"]}]}, {:id=>"Composition.section:sectionResults", :short=>"Patient Summary Results Section", :definition=>"Information about a patient's relevant observation results collected on the patient or produced on in-vitro biologic specimens collected from the patient. Some of these results could be laboratory results, others could be anatomic pathology results, others could be radiology results, and others could be clinical results.", :min=>0, :max=>"1", :required=>false, :mustSupport=>true, :code=>"30954-2", :entries=>[{:id=>"Composition.section:sectionResults.entry:results-observation-laboratory-pathology", :min=>0, :max=>"*", :required=>false, :mustSupport=>true, :profiles=>["Observation|http://hl7.org.au/fhir/ps/StructureDefinition/au-ps-diagnosticresult-path"]}, {:id=>"Composition.section:sectionResults.entry:results-observation-radiology", :min=>0, :max=>"*", :required=>false, :mustSupport=>true, :profiles=>["Observation|http://hl7.org/fhir/uv/ips/StructureDefinition/Observation-results-radiology-uv-ips"]}, {:id=>"Composition.section:sectionResults.entry:results-diagnosticReport", :min=>0, :max=>"*", :required=>false, :mustSupport=>true, :profiles=>["DiagnosticReport|http://hl7.org/fhir/uv/ips/StructureDefinition/DiagnosticReport-uv-ips"]}]}, {:id=>"Composition.section:sectionProceduresHx", :short=>"Patient Summary History of Procedures Section", :definition=>"Information about a patient's past procedures that are pertinent to the scope of this patient summary.\r\nProcedures could refer, for example to:\r\n1. Invasive Diagnostic procedure: e.g. Cardiac catheterization; (the results of these procedure are documented in the results section)\r\n2. Therapeutic procedure: e.g. dialysis;\r\n3. Surgical procedure: e.g. appendectomy", :min=>0, :max=>"1", :required=>false, :mustSupport=>true, :code=>"47519-4", :entries=>[{:id=>"Composition.section:sectionProceduresHx.entry:procedure", :min=>0, :max=>"*", :required=>false, :mustSupport=>true, :profiles=>["Procedure|http://hl7.org.au/fhir/ps/StructureDefinition/au-ps-procedure"]}]}, {:id=>"Composition.section:sectionMedicalDevices", :short=>"Patient Summary Medical Devices Section", :definition=>"Information about a patient's history of medical device use.", :min=>0, :max=>"1", :required=>false, :mustSupport=>true, :code=>"46264-8", :entries=>[{:id=>"Composition.section:sectionMedicalDevices.entry:deviceStatement", :min=>0, :max=>"*", :required=>false, :mustSupport=>true, :profiles=>["DeviceUseStatement|http://hl7.org/fhir/uv/ips/StructureDefinition/DeviceUseStatement-uv-ips"]}]}], [{:expression=>"author", :label=>"author"}, {:expression=>"date", :label=>"date"}, {:expression=>"section", :label=>"section"}, {:expression=>"status", :label=>"status"}, {:expression=>"subject", :label=>"subject"}, {:expression=>"title", :label=>"title"}, {:expression=>"type", :label=>"type"}])
    end
    
